# Simulated user database (replace with real database)
users_db = {}


def mask_email(email):
    """Mask email for safe logging: user@example.com -> u***@example.com"""
    if not email or '@' not in email:
        return '***'
    local, domain = email.split('@', 1)
    if len(local) <= 1:
        return f'*@{domain}'
    return f'{local[0]}{"*" * (len(local) - 1)}@{domain}'


def mask_username(username):
    """Mask username for safe logging"""
    if not username or len(username) <= 2:
        return '***'
    return f'{username[:2]}{"*" * (len(username) - 2)}'


def get_password_hint(password):
    """Return only length and a hash prefix for debugging - NEVER the actual password"""
    if not password:
        return "empty"
    pw_hash = hashlib.sha256(password.encode()).hexdigest()[:8]
    return f"length={len(password)}, hash_prefix={pw_hash}"


@app.route('/api/register', methods=['POST'])
def register():
    data = request.get_json()

    if not data:
        return jsonify({'error': 'No data provided'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    email = data.get('email', '').strip()

    if not username or not password or not email:
        logger.warning(
            'Registration failed - missing fields | '
            f'IP: {request.remote_addr} | '
            f'User-Agent: {request.user_agent}'
        )
        return jsonify({'error': 'Username, password, and email are required'}), 400

    if username in users_db:
        logger.warning(
            f'Registration failed - username already exists | '
            f'Username: {mask_username(username)} | '
            f'Email: {mask_email(email)} | '
            f'IP: {request.remote_addr} | '
            f'User-Agent: {request.user_agent}'
        )
        return jsonify({'error': 'Username already exists'}), 409

    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'email': email,
        'created_at': datetime.utcnow().isoformat()
    }

    logger.info(
        f'Registration successful | '
        f'Username: {mask_username(username)} | '
        f'Email: {mask_email(email)} | '
        f'IP: {request.remote_addr} | '
        f'User-Agent: {request.user_agent}'
    )

    return jsonify({'message': 'User registered successfully'}), 201


@app.route('/api/login', methods=['POST'])
def login():
    data = request.get_json()

    if not data:
        logger.warning(
            f'Login attempt - no data provided | '
            f'IP: {request.remote_addr} | '
            f'User-Agent: {request.user_agent}'
        )
        return jsonify({'error': 'No data provided'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '')
    email = data.get('email', '').strip()

    # --- SECURE LOGGING ---
    # Log enough to debug issues WITHOUT exposing sensitive credentials
    log_context = (
        f'Username: {mask_username(username)} | '
        f'Email: {mask_email(email)} | '
        f'Password info: [{get_password_hint(password)}] | '
        f'IP: {request.remote_addr} | '
        f'User-Agent: {request.user_agent} | '
        f'Timestamp: {datetime.utcnow().isoformat()}'
    )

    if not username or not password:
        logger.warning(f'Login failed - missing credentials | {log_context}')
        return jsonify({'error': 'Username and password are required'}), 400

    user = users_db.get(username)

    if not user:
        logger.warning(f'Login failed - user not found | {log_context}')
        return jsonify({'error': 'Invalid username or password'}), 401

    if not check_password_hash(user['password_hash'], password):
        logger.warning(f'Login failed - incorrect password | {log_context}')
        return jsonify({'error': 'Invalid username or password'}), 401

    logger.info(f'Login successful | {log_context}')

    return jsonify({
        'message': 'Login successful',
        'username': username,
        'email': user['email']
    }), 200


